+        return -1;
+      const gap = previous < 0 ? position : position - previous - 1;
+      gaps += gap;
+      streak = gap === 0 ? streak + 1 : 0;
+      score += 20 + streak * 14;
+      if (position === 0 || " -_./".includes(text[position - 1]))
+        score += 45;
+      previous = position;
+    }
+
+    score -= gaps * 3;
+    score -= Math.max(0, name.length - query.length) * 0.2;
+    return score;
+  }
